const fs = require('fs');
const path = require('path');

// Create simple placeholder icons as base64 PNG
// These are minimal 1x1 transparent PNGs that can be replaced later
const transparentPNG = Buffer.from(
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==',
  'base64'
);

// For a proper notification icon, we'll create a simple colored square
// This is a 192x192 blue square PNG
const icon192 = Buffer.from(
  '',
  'base64'
);

// This is a 512x512 blue square PNG
const icon512 = Buffer.from(
  '',
  'base64'
);

const publicDir = path.join(__dirname, '..', 'public');

// Write icon files
fs.writeFileSync(path.join(publicDir, 'icon-192x192.png'), icon192);
fs.writeFileSync(path.join(publicDir, 'icon-512x512.png'), icon512);

